mapper.select:
SELECT  
  FROM  TB_CPYRHT_INFO A
 WHERE  A.CPYRHT_ID = #{cpyrhtId}

mapper.insert:
INSERT  INTO TB_CPYRHT_INFO
      ( CPYRHT_ID
      , CPYRHT_PRTC_POLICY_CN
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{cpyrhtId}
        , #{cpyrhtPrtcPolicyCn}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_CPYRHT_INFO
   SET  CPYRHT_PRTC_POLICY_CN = #{cpyrhtPrtcPolicyCn}
      , LAST_UPDUSR_ID = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CPYRHT_ID = #{cpyrhtId}
